"import React from 'react';
import { getDocumentLabel, documentTypeLabels } from '@/lib/utils/document-labels';

interface RiskFactor {
  code: string;
  score: number;
  description: string;
  category: string;
}

interface RiskScore {
  level: string;
  score: number;
  factors: RiskFactor[];
  explanation: string;
  suggestedAction: string;
  calculatedAt: string | Date;
}

interface RiskScoreCardProps {
  score?: RiskScore;
  onRecalculate?: () => void;
  isLoading?: boolean;
}

export function replaceTechnicalNames(text: string): string {
  if (!text) return '';
  let cleanText = text;
  Object.keys(documentTypeLabels).forEach((key) => {
    const regex = new RegExp(key, 'g');
    cleanText = cleanText.replace(regex, getDocumentLabel(key));
  });
  return cleanText;
}

export function formatFactorCode(code: string): string {
  if (code === 'MISSING_REQUIRED_DOCUMENT') return 'Missing Required Document';
